const inboxRow = $('Claim Inbox Row').first()?.json ?? {};
const payload = inboxRow.payload ?? {};
const messageBody = typeof payload === 'string' ? (JSON.parse(payload).messageBody ?? '') : (payload.messageBody ?? '');
return [{ json: { messageBody } }];

const scriptRow = $('Fetch Screening Script').first()?.json ?? {};
const questions = scriptRow.questions ?? [];
const state = $('Fetch Screening State').first()?.json ?? {};
const questionIndex = state.question_index ?? 0;
const currentQuestion = questions[questionIndex] ?? null;
const totalQuestions = questions.length;
return [{ json: { currentQuestion, questionIndex, totalQuestions } }];

const content = ($('Normalise Answer — Haiku').first()?.json?.content ?? '').trim().toLowerCase();
const currentQ = $('Get Current Question').first()?.json?.currentQuestion ?? {};
if (content === 'unclear' || content === '') {
  return [{ json: { valid: false, canonical: null, reason: 'unclear' } }];
}
if (currentQ.type === 'yes_no') {
  if (content === 'yes' || content === 'no') {
    return [{ json: { valid: true, canonical: content } }];
  }
  return [{ json: { valid: false, canonical: null, reason: 'unrecognised_yes_no' } }];
}
if (currentQ.type === 'enum') {
  const enumVals = (currentQ.enum_values ?? []).map(v => String(v).toLowerCase());
  if (enumVals.includes(content)) {
    return [{ json: { valid: true, canonical: content } }];
  }
  return [{ json: { valid: false, canonical: null, reason: 'unrecognised_enum' } }];
}
// free_text presence_only: any non-empty non-UNCLEAR is valid
if (currentQ.scoring === 'presence_only') {
  return [{ json: { valid: true, canonical: content } }];
}
// free_text with explicit scoring
const pts = (currentQ.scoring ?? {})[content];
if (pts !== undefined) {
  return [{ json: { valid: true, canonical: content } }];
}
// unknown free_text value with explicit scoring — treat as unclear
return [{ json: { valid: false, canonical: null, reason: 'unrecognised_free_text' } }];

const currentQ = $('Get Current Question').first()?.json?.currentQuestion ?? {};
const raw = ($('Extract Reply Text').first()?.json?.messageBody ?? '').trim();
const lower = raw.toLowerCase();
if (currentQ.type === 'yes_no') {
  const yesWords = ['yes','yeah','yep','yah','y','true','1','absolutely','sure','ok','okay'];
  const noWords = ['no','nope','nah','n','false','0','not','never'];
  if (yesWords.some(w => lower === w || lower.startsWith(w + ' '))) {
    return [{ json: { valid: true, canonical: 'yes' } }];
  }
  if (noWords.some(w => lower === w || lower.startsWith(w + ' '))) {
    return [{ json: { valid: true, canonical: 'no' } }];
  }
  // Ghanaian context: transport ownership patterns
  const yesPatterns = [/okada/i, /motorbike/i, /motor.?bike/i, /\bi drive\b/i, /\bi own\b/i, /every\s*day/i, /\bi have (a |one |my )?motor/i, /\bi use motor/i];
  if (yesPatterns.some(p => p.test(lower))) {
    return [{ json: { valid: true, canonical: 'yes' } }];
  }
  const noPatterns = [/i don'?t (have|own|drive|use)/i, /no motor/i, /no okada/i, /i cannot/i, /i can'?t/i];
  if (noPatterns.some(p => p.test(lower))) {
    return [{ json: { valid: true, canonical: 'no' } }];
  }
  return [{ json: { valid: false, canonical: null, reason: 'unrecognised_yes_no' } }];
}
if (currentQ.type === 'number') {
  const n = parseFloat(raw.replace(/[^0-9.]/g, ''));
  if (!isNaN(n)) {
    return [{ json: { valid: true, canonical: String(n) } }];
  }
  return [{ json: { valid: false, canonical: null, reason: 'not_a_number' } }];
}
if (currentQ.type === 'enum') {
  const enumVals = (currentQ.enum_values ?? []).map(v => String(v).toLowerCase());
  const normalised = lower.replace(/[^a-z0-9_]/g, '_');
  if (enumVals.includes(lower)) {
    return [{ json: { valid: true, canonical: lower } }];
  }
  if (enumVals.includes(normalised)) {
    return [{ json: { valid: true, canonical: normalised } }];
  }
  return [{ json: { valid: false, canonical: null, reason: 'unrecognised_enum' } }];
}
if (currentQ.type === 'presence_only') {
  const present = raw.length > 0;
  return [{ json: { valid: present, canonical: present ? raw : null, reason: present ? null : 'empty_response' } }];
}
return [{ json: { valid: false, canonical: null, reason: 'unknown_type' } }];

function normaliseYesNo(raw) {
  if (!raw) return null;
  const s = String(raw).toLowerCase().trim();
  if (['yes','yeah','yep','y','1','true'].includes(s)) return 'yes';
  if (['no','nope','nah','n','0','false'].includes(s)) return 'no';
  return null;
}
function scoreNumberTiered(n, ranges) {
  if (!ranges || !ranges.length) return 0;
  for (const range of ranges) {
    if (range.max === null || range.max === undefined || n <= range.max) return range.points;
  }
  return ranges[ranges.length - 1]?.points ?? 0;
}
function scoreToTier(score) {
  if (score >= 80) return 'top20';
  if (score >= 60) return 'solid';
  if (score >= 40) return 'developing';
  return 'not_a_fit';
}
function computeScore(questions, answers) {
  const breakdown = {};
  let totalScore = 0;
  for (const q of questions) {
    const raw = answers[q.id] ?? null;
    if (q.type === 'yes_no') {
      const canonical = normaliseYesNo(raw);
      const pts = canonical !== null ? (q.scoring[canonical] ?? 0) : 0;
      breakdown[q.id] = { raw, canonical, pts, weight: q.weight };
      totalScore += pts;
    } else if (q.type === 'number') {
      const n = parseFloat(raw);
      const pts = isNaN(n) ? 0 : scoreNumberTiered(n, q.tiered_scoring);
      breakdown[q.id] = { raw, n, pts, weight: q.weight };
      totalScore += pts;
    } else if (q.type === 'enum') {
      const canonical = (raw ?? '').toLowerCase();
      const pts = q.scoring[canonical] ?? 0;
      breakdown[q.id] = { raw, canonical, pts, weight: q.weight };
      totalScore += pts;
    } else if (q.type === 'presence_only') {
      const present = raw !== null && String(raw).trim().length > 0;
      const maxPts = Object.values(q.scoring)[0] ?? 5;
      const pts = present ? maxPts : 0;
      breakdown[q.id] = { raw, present, pts, weight: q.weight };
      totalScore += pts;
    } else if (q.type === 'free_text') {
      if (q.scoring === 'presence_only') {
        const present = raw !== null && String(raw).trim().length > 0;
        const pts = present ? 5 : 0;
        breakdown[q.id] = { raw, present, pts, weight: q.weight };
        totalScore += pts;
      } else {
        const canonical = (raw ?? '').toLowerCase();
        const pts = q.scoring[canonical] ?? 0;
        breakdown[q.id] = { raw, canonical, pts, weight: q.weight };
        totalScore += pts;
      }
    }
  }
  return { score: totalScore, breakdown, strengthTier: scoreToTier(totalScore) };
}
const storeRow = $('Store Answer + Advance').first()?.json ?? {};
const scriptRow = $('Fetch Screening Script').first()?.json ?? {};
const questions = scriptRow.questions ?? [];
const answers = storeRow.answers ?? {};
const result = computeScore(questions, answers);
const shortlistThreshold = Number(scriptRow.shortlist_threshold ?? 60);
const reEngagementEligible = result.score >= shortlistThreshold;
return [{ json: { finalScore: result.score, breakdown: result.breakdown, strengthTier: result.strengthTier, reEngagementEligible, candidateId: storeRow.candidate_id ?? $('Claim Inbox Row').first()?.json?.candidate_id ?? '', applicationId: storeRow.application_id ?? $('Claim Inbox Row').first()?.json?.application_id ?? '' } }];

const allApps = $('Fetch Blue Collar Applications from Twenty').first()?.json?.data?.applications?.edges ?? [];
const knownIds = new Set(
  $('Fetch Known Application IDs').all().map(item => item.json.application_id)
);
const newApps = allApps
  .map(e => e.node)
  .filter(app => !knownIds.has(app.id));
return [{ json: { newApplications: newApps } }];

const apps = $('Filter New Applications').first()?.json?.newApplications ?? [];
const batchIndex = $nodeContext('Split New Applications')?.currentRunIndex ?? 0;
const app = apps[batchIndex] ?? apps[0] ?? {};
return [{ json: app }];

const app = $('Fetch Application from Twenty — Init').first()?.json?.data?.application ?? {};
const collarType = (app.jobPosting?.collarType ?? '').toUpperCase();
// v1 mapping: BLUE → driver_v1 (only loaded script)
const scriptMap = { 'BLUE': 'driver_v1' };
const scriptId = scriptMap[collarType] ?? 'driver_v1';
return [{ json: { scriptId, collarType } }];
